import{_ as a,c as e,o as i,a1 as o}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Diff 뷰: 여러 각도에서 변경 사항 검토 | Plannotator","description":"Plannotator 코드 리뷰에서 diff 유형을 전환하는 방법을 알아보세요. 드롭다운 메뉴에서 uncommitted, staged, last commit 또는 branch 뷰를 선택하여 여러 각도에서 코드 변경 사항을 검토합니다.","frontmatter":{"title":"Diff 뷰: 여러 각도에서 변경 사항 검토 | Plannotator","sidebarTitle":"5가지 diff 뷰 전환","subtitle":"Diff 뷰: 여러 각도에서 변경 사항 검토","description":"Plannotator 코드 리뷰에서 diff 유형을 전환하는 방법을 알아보세요. 드롭다운 메뉴에서 uncommitted, staged, last commit 또는 branch 뷰를 선택하여 여러 각도에서 코드 변경 사항을 검토합니다.","tags":["code-review","git","diff","tutorial"],"prerequisite":["code-review-basics"],"order":6},"headers":[],"relativePath":"ko/backnotprop/plannotator/platforms/code-review-diff-types/index.md","filePath":"ko/backnotprop/plannotator/platforms/code-review-diff-types/index.md"}'),d={name:"ko/backnotprop/plannotator/platforms/code-review-diff-types/index.md"};function r(s,t,n,l,p,c){return i(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="diff-뷰-전환" tabindex="-1">Diff 뷰 전환 <a class="header-anchor" href="#diff-뷰-전환" aria-label="Permalink to &quot;Diff 뷰 전환&quot;">​</a></h1><h2 id="학습-완료-후-가능한-것" tabindex="-1">학습 완료 후 가능한 것 <a class="header-anchor" href="#학습-완료-후-가능한-것" aria-label="Permalink to &quot;학습 완료 후 가능한 것&quot;">​</a></h2><p>코드 리뷰 시 다음을 수행할 수 있습니다:</p><ul><li>드롭다운 메뉴로 5가지 diff 뷰 간에 빠르게 전환</li><li>각 뷰에서 표시되는 코드 변경 범위 이해</li><li>검토 요구에 따라 적절한 diff 유형 선택</li><li>잘못된 뷰 선택으로 인한 중요한 변경 누락 방지</li></ul><h2 id="현재-겪고-있는-문제" tabindex="-1">현재 겪고 있는 문제 <a class="header-anchor" href="#현재-겪고-있는-문제" aria-label="Permalink to &quot;현재 겪고 있는 문제&quot;">​</a></h2><p><strong>리뷰 시 작업 디렉토리만 보고 스테이징된 파일 누락</strong>:</p><p><code>/plannotator-review</code> 명령을 실행하여 일부 코드 변경 사항을 보고, 몇 개의 주석을 추가했습니다. 하지만 커밋 후에 리뷰에서 이미 <code>git add</code>로 스테이징한 파일들이 누락되었다는 것을 발견했습니다 — 이 파일들은 diff에 전혀 나타나지 않았습니다.</p><p><strong>현재 브랜치와 main 브랜치의 전체 차이점 알고 싶음</strong>:</p><p>수주 동안 기능 브랜치에서 개발했고, 총 무엇을 변경했는지 보고 싶지만 기본 &quot;Uncommitted changes&quot; 뷰는 최근 며칠의 수정만 표시합니다.</p><p><strong>두 특정 커밋 간의 차이점을 비교하고 싶음</strong>:</p><p>특정 버그 수정이 올바른지 확인하기 위해 수정 전후의 코드를 비교해야 하지만, Plannotator에서 과거 커밋 diff를 표시하는 방법을 알지 못합니다.</p><h2 id="활용-시점" tabindex="-1">활용 시점 <a class="header-anchor" href="#활용-시점" aria-label="Permalink to &quot;활용 시점&quot;">​</a></h2><ul><li><strong>포괄적 검토 시</strong>: 작업 디렉토리와 스테이징 영역의 변경 사항을 동시에 확인</li><li><strong>브랜치 병합 전</strong>: main/master 브랜치에 대한 현재 브랜치의 모든 변경 사항 확인</li><li><strong>롤백 검토 시</strong>: 마지막 커밋에서 변경된 파일 확인</li><li><strong>협업 시</strong>: 동료가 스테이징했지만 아직 커밋하지 않은 코드 검토</li></ul><h2 id="핵심-개념" tabindex="-1">핵심 개념 <a class="header-anchor" href="#핵심-개념" aria-label="Permalink to &quot;핵심 개념&quot;">​</a></h2><p>Git diff 명령에는 여러 변형이 있으며, 각각 다른 코드 범위를 표시합니다. Plannotator는 이러한 변형들을 하나의 드롭다운 메뉴로 통합하여 복잡한 git 명령을 기억할 필요가 없도록 만들었습니다.</p><div class="info custom-block"><p class="custom-block-title">Git Diff 유형 빠른 참조</p><table tabindex="0"><thead><tr><th>diff 유형</th><th>표시 범위</th><th>전형적인 사용 시나리오</th></tr></thead><tbody><tr><td>Uncommitted changes</td><td>작업 디렉토리 + 스테이징 영역</td><td>이번 개발의 모든 수정 리뷰</td></tr><tr><td>Staged changes</td><td>스테이징 영역만</td><td>커밋 전 제출할 내용 검토</td></tr><tr><td>Unstaged changes</td><td>작업 디렉토리만</td><td>아직 <code>git add</code>하지 않은 수정 검토</td></tr><tr><td>Last commit</td><td>최근 커밋</td><td>롤백하거나 방금 커밋한 것 검토</td></tr><tr><td>vs main</td><td>현재 브랜치 vs 기본 브랜치</td><td>브랜치 병합 전 포괄적 검토</td></tr></tbody></table></div><p>드롭다운 메뉴의 옵션은 Git 상태에 따라 동적으로 변경됩니다:</p><ul><li>현재 기본 브랜치에 없으면 &quot;vs main&quot; 옵션이 표시됩니다</li><li>스테이징된 파일이 없으면 Staged 뷰가 &quot;No staged changes&quot;를 표시합니다</li></ul><h2 id="따라해-보세요" tabindex="-1">따라해 보세요 <a class="header-anchor" href="#따라해-보세요" aria-label="Permalink to &quot;따라해 보세요&quot;">​</a></h2><h3 id="_1단계-코드-리뷰-시작" tabindex="-1">1단계: 코드 리뷰 시작 <a class="header-anchor" href="#_1단계-코드-리뷰-시작" aria-label="Permalink to &quot;1단계: 코드 리뷰 시작&quot;">​</a></h3><p><strong>이유</strong></p><p>먼저 Plannotator의 코드 리뷰 인터페이스를 열어야 합니다.</p><p><strong>작업</strong></p><p>터미널에서 다음을 실행하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plannotator-review</span></span></code></pre></div><p><strong>예상 결과</strong></p><p>브라우저에서 코드 리뷰 페이지가 열리고 왼쪽 파일 트리 상단에 현재 diff 유형을 표시하는 드롭다운 메뉴가 있습니다(보통 &quot;Uncommitted changes&quot;).</p><h3 id="_2단계-staged-뷰로-전환" tabindex="-1">2단계: Staged 뷰로 전환 <a class="header-anchor" href="#_2단계-staged-뷰로-전환" aria-label="Permalink to &quot;2단계: Staged 뷰로 전환&quot;">​</a></h3><p><strong>이유</strong></p><p>이미 <code>git add</code>했지만 아직 커밋하지 않은 파일을 봅니다.</p><p><strong>작업</strong></p><ol><li>왼쪽 파일 트리 상단의 드롭다운 메뉴 클릭</li><li>&quot;Staged changes&quot; 선택</li></ol><p><strong>예상 결과</strong></p><ul><li>스테이징된 파일이 있으면 파일 트리에서 해당 파일들을 표시</li><li>스테이징된 파일이 없으면 주 영역에 &quot;No staged changes. Stage some files with git add.&quot; 메시지 표시</li></ul><h3 id="_3단계-last-commit-뷰로-전환" tabindex="-1">3단계: Last Commit 뷰로 전환 <a class="header-anchor" href="#_3단계-last-commit-뷰로-전환" aria-label="Permalink to &quot;3단계: Last Commit 뷰로 전환&quot;">​</a></h3><p><strong>이유</strong></p><p>방금 커밋한 코드를 검토하여 문제가 없는지 확인합니다.</p><p><strong>작업</strong></p><ol><li>드롭다운 메뉴를 다시 열기</li><li>&quot;Last commit&quot; 선택</li></ol><p><strong>예상 결과</strong></p><ul><li>최근 커밋에서 수정한 모든 파일 표시</li><li>diff 내용은 <code>HEAD~1..HEAD</code>의 차이점</li></ul><h3 id="_4단계-vs-main-뷰로-전환-사용-가능한-경우" tabindex="-1">4단계: vs main 뷰로 전환(사용 가능한 경우) <a class="header-anchor" href="#_4단계-vs-main-뷰로-전환-사용-가능한-경우" aria-label="Permalink to &quot;4단계: vs main 뷰로 전환(사용 가능한 경우)&quot;">​</a></h3><p><strong>이유</strong></p><p>기본 브랜치에 대한 현재 브랜치의 모든 변경 사항을 봅니다.</p><p><strong>작업</strong></p><ol><li>드롭다운 메뉴에서 &quot;vs main&quot; 또는 &quot;vs master&quot; 옵션이 있는지 확인</li><li>있으면 선택</li></ol><p><strong>예상 결과</strong></p><ul><li>파일 트리가 현재 브랜치와 기본 브랜치 사이의 모든 차이 파일들을 표시</li><li>diff 내용은 <code>main..HEAD</code>의 전체 변경 사항</li></ul><div class="tip custom-block"><p class="custom-block-title">현재 브랜치 확인</p><p>&quot;vs main&quot; 옵션이 보이지 않는다면 기본 브랜치에 있는 것입니다. 다음 명령으로 현재 브랜치를 확인하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> rev-parse</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --abbrev-ref</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEAD</span></span></code></pre></div><p>기능 브랜치로 전환한 후 다시 시도하세요:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div></div><h2 id="검사점-✅" tabindex="-1">검사점 ✅ <a class="header-anchor" href="#검사점-✅" aria-label="Permalink to &quot;검사점 ✅&quot;">​</a></h2><p>다음을 마스터했는지 확인하세요:</p><ul><li>[ ] diff 유형 드롭다운 메뉴를 찾고 열 수 있음</li><li>[ ] &quot;Uncommitted&quot;, &quot;Staged&quot;, &quot;Last commit&quot;의 차이점 이해</li><li>[ ] &quot;vs main&quot; 옵션이 언제 나타나는지 식별</li><li>[ ] 어떤 시나리오에서 어떤 diff 유형을 사용할지 알고 있음</li></ul><h2 id="일반적인-실수" tabindex="-1">일반적인 실수 <a class="header-anchor" href="#일반적인-실수" aria-label="Permalink to &quot;일반적인 실수&quot;">​</a></h2><h3 id="실수-1-리뷰-시-uncommitted만-보고-스테이징된-파일-누락" tabindex="-1">실수 1: 리뷰 시 Uncommitted만 보고 스테이징된 파일 누락 <a class="header-anchor" href="#실수-1-리뷰-시-uncommitted만-보고-스테이징된-파일-누락" aria-label="Permalink to &quot;실수 1: 리뷰 시 Uncommitted만 보고 스테이징된 파일 누락&quot;">​</a></h3><p><strong>증상</strong></p><p>커밋 후에 리뷰에서 일부 스테이징된 파일들이 누락된 것을 발견합니다.</p><p><strong>원인</strong></p><p>Uncommitted 뷰는 작업 디렉토리와 스테이징 영역의 모든 변경 사항을 표시(<code>git diff HEAD</code>)하므로 이미 스테이징된 파일들도 포함됩니다.</p><p><strong>해결</strong></p><p>리뷰 전에 먼저 Staged 뷰로 전환하여 확인하거나 Uncommitted 뷰(스테이징 영역 포함)를 사용하세요.</p><h3 id="실수-2-브랜치-병합-전에-main과-비교하지-않음" tabindex="-1">실수 2: 브랜치 병합 전에 main과 비교하지 않음 <a class="header-anchor" href="#실수-2-브랜치-병합-전에-main과-비교하지-않음" aria-label="Permalink to &quot;실수 2: 브랜치 병합 전에 main과 비교하지 않음&quot;">​</a></h3><p><strong>증상</strong></p><p>main에 병합한 후 관련 없는 수정이 포함된 것을 발견합니다.</p><p><strong>원인</strong></p><p>최근 며칠의 커밋만 보았고 main에 대한 전체 브랜치 차이점을 비교하지 않았습니다.</p><p><strong>해결</strong></p><p>병합 전에 &quot;vs main&quot; 뷰로 포괄적으로 검토하세요.</p><h3 id="실수-3-뷰-전환-시-주석이-손실된다고-생각함" tabindex="-1">실수 3: 뷰 전환 시 주석이 손실된다고 생각함 <a class="header-anchor" href="#실수-3-뷰-전환-시-주석이-손실된다고-생각함" aria-label="Permalink to &quot;실수 3: 뷰 전환 시 주석이 손실된다고 생각함&quot;">​</a></h3><p><strong>증상</strong></p><p>이전에 추가한 주석이 사라질까 봐 diff 유형 전환을 꺼려합니다.</p><p><strong>원인</strong></p><p>전환 메커니즘을 오해했습니다.</p><p><strong>실제 상황</strong></p><p>diff 유형 전환 시 Plannotator는 이전 주석을 유지합니다 — 여전히 적용될 수 있거나, 관련 없는 주석을 수동으로 삭제할 수 있습니다.</p><h2 id="이번-수업-요약" tabindex="-1">이번 수업 요약 <a class="header-anchor" href="#이번-수업-요약" aria-label="Permalink to &quot;이번 수업 요약&quot;">​</a></h2><p>Plannotator가 지원하는 5가지 diff 유형:</p><table tabindex="0"><thead><tr><th>유형</th><th>Git 명령</th><th>시나리오</th></tr></thead><tbody><tr><td>Uncommitted</td><td><code>git diff HEAD</code></td><td>이번 개발의 모든 수정 리뷰</td></tr><tr><td>Staged</td><td><code>git diff --staged</code></td><td>커밋 전 스테이징 영역 검토</td></tr><tr><td>Unstaged</td><td><code>git diff</code></td><td>작업 디렉토리 수정 검토</td></tr><tr><td>Last commit</td><td><code>git diff HEAD~1..HEAD</code></td><td>롤백하거나 최근 커밋 검토</td></tr><tr><td>vs main</td><td><code>git diff main..HEAD</code></td><td>브랜치 병합 전 포괄적 검토</td></tr></tbody></table><p>뷰 전환은 주석을 손실하지 않으므로 동일하거나 새 주석에 대해 다른 관점에서 볼 수 있습니다.</p><h2 id="다음-수업-예고" tabindex="-1">다음 수업 예고 <a class="header-anchor" href="#다음-수업-예고" aria-label="Permalink to &quot;다음 수업 예고&quot;">​</a></h2><blockquote><p>다음 수업에서 **<a href="./../../advanced/url-sharing/">URL 공유</a>**을 학습합니다.</p><p>학습할 내용:</p><ul><li>리뷰 내용을 URL로 압축하여 동료에게 공유하는 방법</li><li>수신자가 공유된 리뷰 링크를 여는 방법</li><li>공유 모드의 제한 사항과 주의점</li></ul></blockquote><hr><h2 id="부록-소스-코드-참조" tabindex="-1">부록: 소스 코드 참조 <a class="header-anchor" href="#부록-소스-코드-참조" aria-label="Permalink to &quot;부록: 소스 코드 참조&quot;">​</a></h2><details><summary><strong>클릭하여 소스 코드 위치 펼치기</strong></summary><blockquote><p>업데이트 시간: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>기능</th><th>파일 경로</th><th>행 번호</th></tr></thead><tbody><tr><td>Diff 유형 정의</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L10-L15" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>10-15</td></tr><tr><td>Git 컨텍스트 가져오기</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L79-L96" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>79-96</td></tr><tr><td>Git Diff 실행</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/server/git.ts#L101-L147" target="_blank" rel="noreferrer"><code>packages/server/git.ts</code></a></td><td>101-147</td></tr><tr><td>Diff 전환 처리</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/App.tsx#L300-L331" target="_blank" rel="noreferrer"><code>packages/review-editor/App.tsx</code></a></td><td>300-331</td></tr><tr><td>파일 트리에서 Diff 옵션 렌더링</td><td><a href="https://github.com/backnotprop/plannotator/blob/main/packages/review-editor/components/FileTree.tsx" target="_blank" rel="noreferrer"><code>packages/review-editor/components/FileTree.tsx</code></a></td><td>-</td></tr></tbody></table><p><strong>주요 타입</strong>:</p><ul><li><code>DiffType</code>: <code>&#39;uncommitted&#39; | &#39;staged&#39; | &#39;unstaged&#39; | &#39;last-commit&#39; | &#39;branch&#39;</code></li></ul><p><strong>주요 함수</strong>:</p><ul><li><code>getGitContext()</code>: 현재 브랜치, 기본 브랜치 및 사용 가능한 diff 옵션 가져오기</li><li><code>runGitDiff(diffType, defaultBranch)</code>: diff 유형에 따라 해당 git 명령 실행</li></ul><p><strong>주요 API</strong>:</p><ul><li><code>POST /api/diff/switch</code>: diff 유형 전환, 새 diff 데이터 반환</li></ul></details>',83)])])}const f=a(d,[["render",r]]);export{g as __pageData,f as default};
